section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/aiops.json",
  "type": "object",
  "required": [
    "artefact_id",
    "baseline_window_days",
    "anomaly_algorithms",
    "dynamic_thresholds_tied_to_slo",
    "auto_remediation_risk_policy",
    "approval_matrix",
    "rca_output_includes",
    "owner"
  ],
  "properties": {
    "artefact_id": {
      "type": "string",
      "description": "stable id for this AIOps config snapshot"
    },
    "baseline_window_days": {
      "type": "integer",
      "description": ">= 14"
    },
    "anomaly_algorithms": {
      "type": "array",
      "description": "non-empty subset of [isolation-forest, prophet, lstm]"
    },
    "dynamic_thresholds_tied_to_slo": {
      "type": "boolean",
      "description": "true"
    },
    "auto_remediation_risk_policy": {
      "type": "object",
      "description": "{low:'auto', medium:'notify-then-timeout', high:'require-approval'}"
    },
    "approval_matrix": {
      "type": "object",
      "description": "{p1: 'require-human', p2: 'require-human', p3: 'optional', p4: 'optional'}"
    },
    "rca_output_includes": {
      "type": "array",
      "description": "must contain ['ranked_causes', 'timeline', 'scope', 'logs_traces']"
    },
    "owner": {
      "type": "string",
      "description": "single named handle"
    }
  }
}
